package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.assertThrows;
import static org.mockito.Mockito.mock;
import static org.mockito.Mockito.when;

import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    void testValidate() {
        CSVFormat csvFormat = new CSVFormat(',', '"', null, null, null, false, true, "\r\n", null, null, false, false);

        assertThrows(IllegalArgumentException.class, csvFormat::validate);

        csvFormat = new CSVFormat(',', '"', null, null, '\\', false, true, "\r\n", null, null, false, false);
        assertThrows(IllegalArgumentException.class, csvFormat::validate);

        csvFormat = new CSVFormat(',', '"', null, '#', null, false, true, "\r\n", null, null, false, false);
        assertThrows(IllegalArgumentException.class, csvFormat::validate);

        csvFormat = new CSVFormat(',', '#', null, '#', null, false, true, "\r\n", null, null, false, false);
        assertThrows(IllegalArgumentException.class, csvFormat::validate);

        csvFormat = new CSVFormat(',', null, QuoteMode.NONE, null, null, false, true, "\r\n", null, null, false, false);
        assertThrows(IllegalArgumentException.class, csvFormat::validate);
    }
}
